/**
 * @file history.ts
 * @description Action-based undo/redo history manager.
 * Migrated from history_manager.js.
 */
import { g, layers } from './globals';
// ─── History Manager ───────────────────────────────────────
export class HistoryManager {
    constructor(maxSteps = 200) {
        this.actions = [];
        this.currentIndex = -1;
        this.maxSteps = maxSteps;
    }
    push(action) {
        // Branching: discard future actions when a new one is recorded
        if (this.currentIndex < this.actions.length - 1) {
            this.actions = this.actions.slice(0, this.currentIndex + 1);
        }
        this.actions.push(action);
        this.currentIndex++;
        if (this.actions.length > this.maxSteps) {
            this.actions.shift();
            this.currentIndex--;
        }
        this.updateUI();
    }
    undo() {
        if (this.currentIndex < 0)
            return;
        const action = this.actions[this.currentIndex];
        console.log(`Undo: ${action.description}`);
        action.undo();
        this.currentIndex--;
        this.updateUI();
    }
    redo() {
        if (this.currentIndex >= this.actions.length - 1)
            return;
        this.currentIndex++;
        const action = this.actions[this.currentIndex];
        console.log(`Redo: ${action.description}`);
        action.redo();
        this.updateUI();
    }
    jumpTo(targetIndex) {
        if (targetIndex === this.currentIndex)
            return;
        if (targetIndex < this.currentIndex) {
            while (this.currentIndex > targetIndex)
                this.undo();
        }
        else {
            while (this.currentIndex < targetIndex)
                this.redo();
        }
    }
    clear() {
        this.actions = [];
        this.currentIndex = -1;
        this.updateUI();
    }
    get canUndo() { return this.currentIndex >= 0; }
    get canRedo() { return this.currentIndex < this.actions.length - 1; }
    updateUI() {
        const pane = document.getElementById('history-pane');
        if (!pane)
            return;
        const list = pane.querySelector('.history-list');
        if (!list)
            return;
        list.innerHTML = '';
        // Initial "Open" state
        const openItem = document.createElement('div');
        openItem.className = `history-item${this.currentIndex === -1 ? ' active' : ''}`;
        openItem.innerHTML = `<div class="history-item-icon">📝</div><div class="history-item-text">Open</div>`;
        openItem.onclick = () => this.jumpTo(-1);
        list.appendChild(openItem);
        this.actions.forEach((action, index) => {
            const item = document.createElement('div');
            const isPast = index > this.currentIndex;
            item.className =
                `history-item` +
                    (index === this.currentIndex ? ' active' : '') +
                    (isPast ? ' ghosted' : '');
            if (isPast)
                item.style.opacity = '0.5';
            let icon = '⚡';
            if (action.description.includes('Draw'))
                icon = '✏️';
            if (action.description.includes('Layer'))
                icon = '📄';
            if (action.description.includes('Vector'))
                icon = '🔷';
            if (action.description.includes('Property') || action.description.includes('Change'))
                icon = '⚙️';
            if (action.description.includes('Add'))
                icon = '➕';
            if (action.description.includes('Edit'))
                icon = '📝';
            item.innerHTML = `<div class="history-item-icon">${icon}</div><div class="history-item-text">${action.description}</div>`;
            item.onclick = () => this.jumpTo(index);
            list.appendChild(item);
        });
        const activeItem = list.querySelector('.history-item.active');
        if (activeItem)
            activeItem.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
    }
}
// ─── Action Implementations ────────────────────────────────
export class DrawAction {
    constructor(layerIndex, previousImageData, newImageData) {
        this.description = 'Draw';
        this.layerIndex = layerIndex;
        this.previousImageData = previousImageData;
        this.newImageData = newImageData;
    }
    undo() {
        const layer = layers[this.layerIndex];
        if (layer) {
            layer.ctx.putImageData(this.previousImageData, 0, 0);
            window.renderLayers?.();
            window.updateLayerPanel?.();
        }
    }
    redo() {
        const layer = layers[this.layerIndex];
        if (layer) {
            layer.ctx.putImageData(this.newImageData, 0, 0);
            window.renderLayers?.();
            window.updateLayerPanel?.();
        }
    }
}
export class LayerAddAction {
    constructor(layerIndex, layerData) {
        this.description = 'Add Layer';
        this.layerIndex = layerIndex;
        this.layerData = layerData;
    }
    undo() {
        layers.splice(this.layerIndex, 1);
        if (g.activeLayerIndex >= layers.length) {
            g.activeLayerIndex = Math.max(0, layers.length - 1);
        }
        window.renderLayers?.();
        window.updateLayerPanel?.();
    }
    redo() {
        layers.splice(this.layerIndex, 0, this.layerData);
        g.activeLayerIndex = this.layerIndex;
        window.renderLayers?.();
        window.updateLayerPanel?.();
    }
}
export class LayerDeleteAction {
    constructor(layerIndex, layerData) {
        this.description = 'Delete Layer';
        this.layerIndex = layerIndex;
        this.layerData = layerData;
    }
    undo() {
        layers.splice(this.layerIndex, 0, this.layerData);
        g.activeLayerIndex = this.layerIndex;
        window.renderLayers?.();
        window.updateLayerPanel?.();
    }
    redo() {
        layers.splice(this.layerIndex, 1);
        if (g.activeLayerIndex >= layers.length) {
            g.activeLayerIndex = Math.max(0, layers.length - 1);
        }
        window.renderLayers?.();
        window.updateLayerPanel?.();
    }
}
export class LayerMoveAction {
    constructor(fromIndex, toIndex) {
        this.description = 'Move Layer';
        this.fromIndex = fromIndex;
        this.toIndex = toIndex;
    }
    undo() { window.moveLayer?.(this.toIndex, this.fromIndex, true); }
    redo() { window.moveLayer?.(this.fromIndex, this.toIndex, true); }
}
export class LayerPropertyAction {
    constructor(layerIndex, property, oldValue, newValue) {
        this.description = `Change ${property}`;
        this.layerIndex = layerIndex;
        this.property = property;
        this.oldValue = oldValue;
        this.newValue = newValue;
    }
    undo() {
        const layer = layers[this.layerIndex];
        if (layer) {
            layer[this.property] = this.oldValue;
            window.renderLayers?.();
            window.updateLayerPanel?.();
        }
    }
    redo() {
        const layer = layers[this.layerIndex];
        if (layer) {
            layer[this.property] = this.newValue;
            window.renderLayers?.();
            window.updateLayerPanel?.();
        }
    }
}
export class VectorAddAction {
    constructor(layerIndex, shape) {
        this.description = `Add ${shape.type.charAt(0).toUpperCase() + shape.type.slice(1)}`;
        this.layerIndex = layerIndex;
        this.shape = JSON.parse(JSON.stringify(shape));
    }
    undo() {
        const layer = layers[this.layerIndex];
        if (layer?.shapes) {
            layer.shapes.pop();
            window.renderVectorLayer?.(layer);
            window.renderLayers?.();
        }
    }
    redo() {
        const layer = layers[this.layerIndex];
        if (layer) {
            if (!layer.shapes)
                layer.shapes = [];
            layer.shapes.push(JSON.parse(JSON.stringify(this.shape)));
            window.renderVectorLayer?.(layer);
            window.renderLayers?.();
        }
    }
}
export class VectorEditAction {
    constructor(layerIndex, shapeIndex, oldShape, newShape) {
        this.description = `Edit ${newShape.type.charAt(0).toUpperCase() + newShape.type.slice(1)}`;
        this.layerIndex = layerIndex;
        this.shapeIndex = shapeIndex;
        this.oldShape = JSON.parse(JSON.stringify(oldShape));
        this.newShape = JSON.parse(JSON.stringify(newShape));
    }
    undo() {
        const layer = layers[this.layerIndex];
        if (layer?.shapes?.[this.shapeIndex]) {
            layer.shapes[this.shapeIndex] = JSON.parse(JSON.stringify(this.oldShape));
            window.renderVectorLayer?.(layer);
            window.renderLayers?.();
        }
    }
    redo() {
        const layer = layers[this.layerIndex];
        if (layer?.shapes?.[this.shapeIndex]) {
            layer.shapes[this.shapeIndex] = JSON.parse(JSON.stringify(this.newShape));
            window.renderVectorLayer?.(layer);
            window.renderLayers?.();
        }
    }
}
// ─── Singleton & Browser Globals ───────────────────────────
export const historyManager = new HistoryManager(g.max_undo_steps);
if (typeof window !== 'undefined') {
    window.historyManager = historyManager;
    window.DrawAction = DrawAction;
    window.LayerAddAction = LayerAddAction;
    window.LayerDeleteAction = LayerDeleteAction;
    window.LayerMoveAction = LayerMoveAction;
    window.LayerPropertyAction = LayerPropertyAction;
    window.VectorAddAction = VectorAddAction;
    window.VectorEditAction = VectorEditAction;
}
