import { g, layers } from '@hcie/core';
import { renderLayers, updateLayerPanel } from '@hcie/canvas-ui';
import { applySepia, applyBoxBlur, applyMelt, applyShear, applyMosaic } from '@hcie/canvas-ui';
/**
 * Filter UI Helper Functions
 * Manages slider updates and applies filters to the active layer.
 * Ported and enhanced from legacy filter_ui.js.
 */
export function updateBlurValue(value) {
    const val = typeof value === 'string' ? parseInt(value) : value;
    const label = document.getElementById('blurRadiusValue');
    if (label)
        label.textContent = val.toString();
    g.blur_radius = val;
}
export function updateMeltValue(value) {
    const val = typeof value === 'string' ? parseInt(value) : value;
    const label = document.getElementById('meltAmountValue');
    if (label)
        label.textContent = val.toString();
    g.melt_amount = val;
}
export function updateShearValue(value) {
    const val = typeof value === 'string' ? parseInt(value) : value;
    const label = document.getElementById('shearAmountValue');
    if (label)
        label.textContent = val.toString();
    g.shear_amount = val;
}
export function updateMosaicValue(value) {
    const val = typeof value === 'string' ? parseInt(value) : value;
    const label = document.getElementById('mosaicSizeValue');
    if (label)
        label.textContent = val.toString();
    g.mosaic_block_size = val;
}
/**
 * Common logic to apply a filter to the active layer
 */
function applyToActiveLayer(filterFn) {
    const layer = layers[g.activeLayerIndex];
    if (!layer || layer.locked || !layer.visible) {
        console.warn('Cannot apply filter: layer is locked, hidden, or selected index invalid');
        return;
    }
    const ctx = layer.ctx;
    const width = layer.canvas.width;
    const height = layer.canvas.height;
    // Capture state for undo
    const oldData = ctx.getImageData(0, 0, width, height);
    // Apply filter
    const imageData = ctx.getImageData(0, 0, width, height);
    const result = filterFn(imageData);
    if (result instanceof ImageData) {
        ctx.putImageData(result, 0, 0);
    }
    else {
        ctx.putImageData(imageData, 0, 0);
    }
    // Record history
    if (window.historyManager) {
        const newData = ctx.getImageData(0, 0, width, height);
        // We need a DrawAction or similar
        const DrawActionClass = window.DrawAction;
        if (DrawActionClass) {
            window.historyManager.push(new DrawActionClass(g.activeLayerIndex, oldData, newData));
        }
    }
    renderLayers();
    updateLayerPanel();
}
export function applyFilterSepia() {
    applyToActiveLayer((imgData) => applySepia(imgData));
}
export function applyFilterBlur() {
    applyToActiveLayer((imgData) => applyBoxBlur(imgData, g.blur_radius || 3));
}
export function applyFilterMelt() {
    applyToActiveLayer((imgData) => applyMelt(imgData, g.melt_amount || 30));
}
export function applyFilterShear() {
    const checkbox = document.getElementById('shearHorizontalCheckbox');
    const horizontal = checkbox ? checkbox.checked : true;
    applyToActiveLayer((imgData) => applyShear(imgData, g.shear_amount || 40, horizontal, g.shear_direction || 1));
}
export function applyFilterMosaic() {
    applyToActiveLayer((imgData) => applyMosaic(imgData, g.mosaic_block_size || 10));
}
// Global exposure for legacy index.html onclick/oninput
window.updateBlurValue = updateBlurValue;
window.updateMeltValue = updateMeltValue;
window.updateShearValue = updateShearValue;
window.updateMosaicValue = updateMosaicValue;
window.applyFilterSepia = applyFilterSepia;
window.applyFilterBlur = applyFilterBlur;
window.applyFilterMelt = applyFilterMelt;
window.applyFilterShear = applyFilterShear;
window.applyFilterMosaic = applyFilterMosaic;
