import { g, layers } from '@hcie/core';
import { historyManager, DrawAction } from '@hcie/core';
import { renderLayers, updateLayerPanel } from '@hcie/canvas-ui';
import { api } from '@hcie/io';
import { ProjectIO } from '@hcie/io';
import { newDocument } from '@hcie/core';
import * as filters from '@hcie/canvas-ui';
/**
 * Menu Handlers
 * This module provides global functions that are called by onclick attributes in index.html.
 * It bridges the modular TypeScript codebase with the legacy HTML-based UI.
 */
// --- File Operations ---
export async function handleOpenFile() {
    try {
        const filePath = await api.openFile();
        if (!filePath)
            return;
        console.log('[handleOpenFile] File selected:', filePath);
        const buffer = await api.readFileBinary(filePath);
        if (!buffer) {
            alert('Could not read file binary data.');
            return;
        }
        console.log('[handleOpenFile] Binary data ready. Importing...');
        const success = await ProjectIO.importImage(buffer.buffer, filePath);
        if (success) {
            g.filepath = filePath;
            const el = document.getElementById('filePath');
            if (el)
                el.innerText = filePath;
            console.log('[handleOpenFile] Import successful.');
        }
    }
    catch (err) {
        console.error('[handleOpenFile] Error:', err);
        alert(`Failed to open file: ${err.message}\nCheck console for details.`);
    }
}
export async function handleSaveFile() {
    try {
        if (!g.filepath || g.filepath.toLowerCase().endsWith('.png') || g.filepath.toLowerCase().endsWith('.jpg') || g.filepath.toLowerCase().endsWith('.gif')) {
            // If no path or path is an image (can't save project as image directly), do Save As
            return handleSaveAsFile();
        }
        const content = await ProjectIO.saveProject();
        const savedPath = await api.saveFile(content, g.filepath, false, 'hcie');
        if (savedPath) {
            console.log('File saved to:', savedPath);
            g.filepath = savedPath;
            const el = document.getElementById('filePath');
            if (el)
                el.innerText = savedPath;
        }
    }
    catch (err) {
        console.error('Save failed:', err);
    }
}
export async function handleSaveAsFile() {
    try {
        // 1. Ask for Format
        const format = await window.DialogHandler.showFormatSelector();
        if (!format)
            return; // User cancelled
        let content;
        let type = format === 'png' ? 'png' : (format === 'psd' ? 'psd' : (format === 'gif' ? 'gif' : 'hcie'));
        // 2. Export/Save using generalized routine
        const extension = "." + type;
        const outContent = await ProjectIO.exportImage(extension);
        // 3. Save File
        const savedPath = await api.saveFile(outContent, g.filepath, true, type);
        if (savedPath) {
            console.log(`File saved as ${format} to:`, savedPath);
            if (type === 'hcie') {
                g.filepath = savedPath;
                const el = document.getElementById('filePath');
                if (el)
                    el.innerText = savedPath;
            }
        }
    }
    catch (err) {
        console.error('Save As failed:', err);
    }
}
export async function handleExportFile() {
    try {
        const activeLayer = layers[g.activeLayerIndex];
        if (!activeLayer)
            return;
        const dataURL = activeLayer.canvas.toDataURL('image/png');
        await api.saveFile(dataURL, g.filepath, true, 'png');
    }
    catch (err) {
        console.error('Export failed:', err);
    }
}
// --- Edit Operations ---
export function undoImage() {
    historyManager.undo();
}
export function redoImage() {
    historyManager.redo();
}
export function clearCanvas() {
    const activeLayer = layers[g.activeLayerIndex];
    if (!activeLayer || activeLayer.locked)
        return;
    const ctx = activeLayer.ctx;
    const oldData = ctx.getImageData(0, 0, g.image_width, g.image_height);
    ctx.clearRect(0, 0, g.image_width, g.image_height);
    const newData = ctx.getImageData(0, 0, g.image_width, g.image_height);
    historyManager.push(new DrawAction(g.activeLayerIndex, oldData, newData));
    renderLayers();
    updateLayerPanel();
}
// --- Filter Operations ---
export function applyFilter(type) {
    const activeLayer = layers[g.activeLayerIndex];
    if (!activeLayer || activeLayer.locked)
        return;
    const ctx = activeLayer.ctx;
    const imageData = ctx.getImageData(0, 0, g.image_width, g.image_height);
    switch (type) {
        case 'negative':
        case 'invert':
            filters.applyNegative(imageData);
            break;
        case 'grayscale':
            filters.applyGrayscale(imageData);
            break;
        case 'sepia':
            filters.applySepia(imageData);
            break;
        case 'blur':
            // Using default radius from globals
            const blurred = filters.applyBoxBlur(imageData, g.blur_radius);
            ctx.putImageData(blurred, 0, 0);
            break;
        case 'mosaic':
            const pixelated = filters.applyMosaic(imageData, g.mosaic_block_size);
            ctx.putImageData(pixelated, 0, 0);
            break;
        default:
            console.warn('Unknown filter type:', type);
            return;
    }
    if (type !== 'blur' && type !== 'mosaic') {
        ctx.putImageData(imageData, 0, 0);
    }
    renderLayers();
    updateLayerPanel();
    // TODO: Add to history
}
// --- View Operations ---
export function zoomIn() {
    if (window.zoomIn) {
        window.zoomIn(null);
    }
}
export function zoomOut() {
    if (window.zoomOut) {
        window.zoomOut(null);
    }
}
// --- New Image Dialog ---
export function closeNewImageDialog() {
    const modal = document.getElementById('newImageModal');
    if (modal)
        modal.style.display = 'none';
}
export function openNewImageDialog() {
    const modal = document.getElementById('newImageModal');
    if (modal) {
        modal.style.display = 'block';
        // Reset to custom or default values if needed
    }
}
export function applyPreset() {
    const preset = document.getElementById('imagePreset').value;
    const widthInput = document.getElementById('newWidth');
    const heightInput = document.getElementById('newHeight');
    switch (preset) {
        case 'hd':
            widthInput.value = '1280';
            heightInput.value = '720';
            break;
        case 'fhd':
            widthInput.value = '1920';
            heightInput.value = '1080';
            break;
        case '4k':
            widthInput.value = '3840';
            heightInput.value = '2160';
            break;
        case 'a4':
            widthInput.value = '2480';
            heightInput.value = '3508';
            break;
        case 'square':
            widthInput.value = '1024';
            heightInput.value = '1024';
            break;
        case 'custom':
            // Don't change values
            break;
    }
}
export function setOrientation(orientation) {
    const widthInput = document.getElementById('newWidth');
    const heightInput = document.getElementById('newHeight');
    const width = parseInt(widthInput.value);
    const height = parseInt(heightInput.value);
    const btnPortrait = document.getElementById('btn-portrait');
    const btnLandscape = document.getElementById('btn-landscape');
    if (orientation === 'portrait') {
        if (width > height) {
            widthInput.value = height.toString();
            heightInput.value = width.toString();
        }
        btnPortrait?.classList.add('btn-active');
        btnLandscape?.classList.remove('btn-active');
    }
    else {
        if (height > width) {
            widthInput.value = height.toString();
            heightInput.value = width.toString();
        }
        btnLandscape?.classList.add('btn-active');
        btnPortrait?.classList.remove('btn-active');
    }
}
export function createNewImage() {
    const width = parseInt(document.getElementById('newWidth').value);
    const height = parseInt(document.getElementById('newHeight').value);
    const name = "Untitled";
    const bgColor = document.getElementById('newBgColor').value;
    const isTransparent = document.getElementById('transparentBg').checked;
    newDocument(name, width, height);
    // After newDocument, the active layer is the Background layer.
    const activeLayer = layers[g.activeLayerIndex];
    if (activeLayer) {
        const ctx = activeLayer.ctx;
        ctx.clearRect(0, 0, width, height);
        if (!isTransparent) {
            ctx.fillStyle = bgColor;
            ctx.fillRect(0, 0, width, height);
        }
    }
    closeNewImageDialog();
    renderLayers();
    updateLayerPanel();
}
export function exitApp() {
    if (window.__TAURI__) {
        // Tauri exit
        try {
            window.__TAURI__.process.exit(0);
        }
        catch (e) {
            console.error('Tauri exit failed:', e);
            window.close();
        }
    }
    else if (window.electronAPI) {
        // Electron exit via API if available
        window.close();
    }
    else {
        // Web fallback
        if (confirm("Are you sure you want to exit? Unsaved changes will be lost.")) {
            window.location.href = "about:blank";
        }
    }
}
// Expose to window
if (typeof window !== 'undefined') {
    Object.assign(window, {
        handleOpenFile,
        openImage: handleOpenFile, // Alias for legacy HTML
        handleSaveFile,
        saveProject: handleSaveFile, // Alias for legacy HTML
        handleSaveAsFile,
        saveAsProject: handleSaveAsFile, // Alias for legacy HTML
        handleExportFile,
        undoImage,
        redoImage,
        clearCanvas,
        applyFilter,
        zoomIn,
        zoomOut,
        closeNewImageDialog,
        openNewImageDialog,
        newCanvas: openNewImageDialog, // Alias for legacy HTML
        exitApp,
        applyPreset,
        setOrientation,
        createNewImage
    });
}
