// ─── Layer Class ───────────────────────────────────────────
export class LayerClass {
    constructor(name = 'Layer', width = g.image_width, height = g.image_height) {
        this.name = name;
        this.canvas = g.createCanvas(width, height);
        // createCanvas returns CanvasLike; getContext('2d') is guaranteed to work
        const ctx = this.canvas.getContext('2d') ??
            this.canvas.getContext('2d');
        if (!ctx)
            throw new Error('Failed to get 2D context for layer canvas');
        this.ctx = ctx;
        this.visible = true;
        this.opacity = 1.0;
        this.blendMode = 'source-over';
        this.locked = false;
        this.type = 'raster';
        this.textData = {
            text: '', x: 0, y: 0,
            font: 'Roboto', size: 40, color: '#000000',
            bold: false, italic: false,
        };
    }
}
